class Solution {
    public int minimizedStringLength(String s) {
        int[] lastOccurrence = new int[26];
        int count = 0;
        for (char c : s.toCharArray()) {
            int index = c - 'a';
            if (lastOccurrence[index] == 0) {
                count++;
            }
            lastOccurrence[index]++;
        }
        return count;
    }
}
